// Generated by Claude Opus 4.6

import { BackupStatus } from '@eclipse-che/common';
import * as k8s from '@kubernetes/client-node';
import { V1Job, V1JobStatus } from '@kubernetes/client-node';

import { BackupApiService } from '@/devworkspaceClient/services/backupApi';

// Mock retryableExec to pass through immediately
jest.mock('@/devworkspaceClient/services/helpers/retryableExec', () => ({
  retryableExec: jest.fn((fn: () => any) => fn()),
}));

describe('BackupApiService', () => {
  let backupApiService: BackupApiService;
  let mockKubeConfig: k8s.KubeConfig;
  let mockCustomObjectAPI: any;
  let mockBatchV1API: any;

  const namespace = 'user-che';
  const workspaceName = 'my-workspace';
  const registry = 'image-registry.openshift-image-registry.svc:5000';
  const expectedImageUrl = `${registry}/${namespace}/${workspaceName}:latest`;

  // Operator config returned directly (no .body wrapper, matching k8s client v1.3.0)
  // Structure matches actual DWO API: enable (not enabled), registry object (not string)
  const mockOperatorConfig = {
    kind: 'DevWorkspaceOperatorConfig',
    config: {
      workspace: {
        backupCronJob: {
          enable: true,
          schedule: '0 1 * * *',
          registry: {
            path: registry,
            authSecret: 'registry-credentials',
          },
          image: 'quay.io/eclipse/che-backup:latest',
          serviceAccount: 'che-workspace',
        },
      },
    },
  };

  // DevWorkspace resource returned directly (no .body wrapper)
  function mockDevWorkspace(annotations: Record<string, string> = {}) {
    return {
      kind: 'DevWorkspace',
      metadata: {
        name: workspaceName,
        namespace,
        annotations,
      },
      status: {
        devworkspaceId: 'workspace-abc123',
      },
    };
  }

  /**
   * Set up getNamespacedCustomObject to return operator config first,
   * then DevWorkspace on the second call. This matches the call order in
   * getWorkspaceBackupStatus: getClusterBackupConfig() → getNamespacedCustomObject for DevWorkspace.
   */
  function mockGetNamespacedForBackupStatus(
    annotations: Record<string, string> = {},
    operatorConfigOverride?: any,
  ) {
    mockCustomObjectAPI.getNamespacedCustomObject
      .mockResolvedValueOnce(operatorConfigOverride ?? mockOperatorConfig) // 1st call: operator config
      .mockResolvedValueOnce(mockDevWorkspace(annotations)); // 2nd call: DevWorkspace
  }

  beforeEach(() => {
    mockKubeConfig = new k8s.KubeConfig();

    mockCustomObjectAPI = {
      getClusterCustomObject: jest.fn(),
      getNamespacedCustomObject: jest.fn(),
    };

    mockBatchV1API = {
      listNamespacedJob: jest.fn(),
    };

    jest.spyOn(mockKubeConfig, 'makeApiClient').mockImplementation((apiType: any) => {
      if (apiType === k8s.CustomObjectsApi) {
        return mockCustomObjectAPI;
      }
      if (apiType === k8s.BatchV1Api) {
        return mockBatchV1API;
      }
      return {};
    });

    backupApiService = new BackupApiService(mockKubeConfig);

    // Default: no active backup Jobs
    mockBatchV1API.listNamespacedJob.mockResolvedValue({ items: [] });
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('getClusterBackupConfig', () => {
    it('should return backup configuration when enabled', async () => {
      // getClusterBackupConfig calls getNamespacedCustomObject (not getClusterCustomObject)
      mockCustomObjectAPI.getNamespacedCustomObject.mockResolvedValue(mockOperatorConfig);

      const result = await backupApiService.getClusterBackupConfig();

      expect(result).toMatchObject({
        enabled: true,
        schedule: '0 1 * * *',
        registry,
        authSecretName: 'registry-credentials',
      });

      expect(mockCustomObjectAPI.getNamespacedCustomObject).toHaveBeenCalledWith({
        group: 'controller.devfile.io',
        version: 'v1alpha1',
        namespace: 'openshift-operators',
        plural: 'devworkspaceoperatorconfigs',
        name: 'devworkspace-operator-config',
      });
    });

    it('should return default values when backup not configured', async () => {
      mockCustomObjectAPI.getNamespacedCustomObject.mockResolvedValue({
        kind: 'DevWorkspaceOperatorConfig',
        config: {},
      });

      const result = await backupApiService.getClusterBackupConfig();

      expect(result).toEqual({
        enabled: false,
        schedule: '',
        registry: '',
        authSecretName: undefined,
      });
    });

    it('should throw error when API call fails', async () => {
      mockCustomObjectAPI.getNamespacedCustomObject.mockRejectedValue(new Error('API Error'));

      await expect(backupApiService.getClusterBackupConfig()).rejects.toThrow(
        'Unable to get cluster backup configuration',
      );
    });
  });

  describe('getWorkspaceBackupStatus', () => {
    it('should return NEVER status when no backup annotations exist', async () => {
      mockGetNamespacedForBackupStatus({});

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.NEVER);
      expect(result.backupSchedule).toBe('0 1 * * *');
    });

    it('should return SUCCESS status from annotations with constructed image URL', async () => {
      const annotations = {
        'controller.devfile.io/last-backup-successful': 'true',
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.SUCCESS);
      expect(result.lastBackupTime).toBe('2025-02-10T01:05:00Z');
      expect(result.backupImageUrl).toBe(expectedImageUrl);
      expect(result.backupSchedule).toBe('0 1 * * *');
      expect(result.error).toBeUndefined();
    });

    it('should return FAILED status from annotations with default error message', async () => {
      const annotations = {
        'controller.devfile.io/last-backup-successful': 'false',
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.FAILED);
      expect(result.error).toBe('Last backup was not successful');
      expect(result.lastBackupTime).toBe('2025-02-10T01:05:00Z');
      expect(result.backupImageUrl).toBeUndefined();
    });

    it('should return FAILED status with error message from annotation', async () => {
      const annotations = {
        'controller.devfile.io/last-backup-successful': 'false',
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
        'controller.devfile.io/last-backup-error':
          'Pod failed with exit code 1: registry auth timeout',
      };
      mockGetNamespacedForBackupStatus(annotations);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.FAILED);
      expect(result.error).toBe('Pod failed with exit code 1: registry auth timeout');
    });

    it('should return IN_PROGRESS when an active backup Job exists', async () => {
      const annotations = {
        'controller.devfile.io/last-backup-successful': 'true',
        'controller.devfile.io/last-backup-finished-at': '2025-02-09T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations);

      const activeJob: V1Job = {
        metadata: {
          name: 'backup-job-active',
          namespace,
          labels: {
            'controller.devfile.io/backup-job': 'true',
            'controller.devfile.io/devworkspace_name': workspaceName,
          },
        },
        status: {
          active: 1,
          startTime: new Date('2025-02-10T00:55:00Z'),
        } as V1JobStatus,
      };
      mockBatchV1API.listNamespacedJob.mockResolvedValue({ items: [activeJob] });

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.IN_PROGRESS);
      expect(result.lastBackupTime).toBe('2025-02-09T01:05:00Z');
      expect(result.backupImageUrl).toBe(expectedImageUrl);
    });

    it('should fall back to annotations when Job query fails', async () => {
      const annotations = {
        'controller.devfile.io/last-backup-successful': 'true',
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations);
      mockBatchV1API.listNamespacedJob.mockRejectedValue(new Error('Forbidden'));

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      // Should not throw; should use annotation-based status
      expect(result.status).toBe(BackupStatus.SUCCESS);
      expect(result.lastBackupTime).toBe('2025-02-10T01:05:00Z');
    });

    it('should return FAILED when only finished-at annotation is present without success annotation', async () => {
      // Edge case: finished-at exists but success annotation missing
      const annotations = {
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      // last-backup-successful is undefined → treated as FAILED (since it's not 'true')
      // But finished-at IS defined, so it doesn't match the NEVER condition
      expect(result.status).toBe(BackupStatus.FAILED);
    });

    it('should read DevWorkspace with correct API parameters', async () => {
      mockGetNamespacedForBackupStatus({});

      await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      // Second call is the DevWorkspace read
      expect(mockCustomObjectAPI.getNamespacedCustomObject).toHaveBeenNthCalledWith(2, {
        group: 'workspace.devfile.io',
        version: 'v1alpha2',
        namespace,
        plural: 'devworkspaces',
        name: workspaceName,
      });
    });

    it('should query Jobs with correct label selector', async () => {
      mockGetNamespacedForBackupStatus({});

      await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(mockBatchV1API.listNamespacedJob).toHaveBeenCalledWith({
        namespace,
        labelSelector: `controller.devfile.io/backup-job=true,controller.devfile.io/devworkspace_name=${workspaceName}`,
      });
    });

    it('should throw error when DevWorkspace API call fails', async () => {
      // First call (operator config) succeeds, second (DevWorkspace) fails
      mockCustomObjectAPI.getNamespacedCustomObject
        .mockResolvedValueOnce(mockOperatorConfig)
        .mockRejectedValueOnce(new Error('Not Found'));

      await expect(
        backupApiService.getWorkspaceBackupStatus(namespace, workspaceName),
      ).rejects.toThrow(`Unable to get backup status for workspace ${workspaceName}`);
    });

    it('should not report IN_PROGRESS for completed Jobs', async () => {
      const annotations = {
        'controller.devfile.io/last-backup-successful': 'true',
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations);

      const completedJob: V1Job = {
        metadata: {
          name: 'backup-job-done',
          namespace,
          labels: {
            'controller.devfile.io/backup-job': 'true',
            'controller.devfile.io/devworkspace_name': workspaceName,
          },
        },
        status: {
          succeeded: 1,
          completionTime: new Date('2025-02-10T01:05:00Z'),
        } as V1JobStatus,
      };
      mockBatchV1API.listNamespacedJob.mockResolvedValue({ items: [completedJob] });

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.SUCCESS);
    });

    it('should return undefined backupImageUrl when registry is not configured', async () => {
      const operatorConfigNoRegistry = {
        kind: 'DevWorkspaceOperatorConfig',
        config: {
          workspace: {
            backupCronJob: {
              enable: true,
              schedule: '0 1 * * *',
              registry: {
                path: '',
              },
            },
          },
        },
      };

      const annotations = {
        'controller.devfile.io/last-backup-successful': 'true',
        'controller.devfile.io/last-backup-finished-at': '2025-02-10T01:05:00Z',
      };
      mockGetNamespacedForBackupStatus(annotations, operatorConfigNoRegistry);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.status).toBe(BackupStatus.SUCCESS);
      expect(result.backupImageUrl).toBeUndefined();
    });
  });

  describe('backup schedule passthrough', () => {
    it('should pass the raw cron expression as backupSchedule', async () => {
      mockGetNamespacedForBackupStatus({});

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.backupSchedule).toBe('0 1 * * *');
    });

    it('should pass invalid cron expression as-is', async () => {
      const operatorConfigBadCron = {
        kind: 'DevWorkspaceOperatorConfig',
        config: {
          workspace: {
            backupCronJob: {
              enable: true,
              schedule: 'invalid-cron',
              registry: {
                path: 'registry.example.com',
              },
            },
          },
        },
      };
      mockGetNamespacedForBackupStatus({}, operatorConfigBadCron);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.backupSchedule).toBe('invalid-cron');
    });

    it('should handle empty schedule string', async () => {
      const operatorConfigNoSchedule = {
        kind: 'DevWorkspaceOperatorConfig',
        config: {
          workspace: {
            backupCronJob: {
              enable: true,
              schedule: '',
              registry: {
                path: 'registry.example.com',
              },
            },
          },
        },
      };
      mockGetNamespacedForBackupStatus({}, operatorConfigNoSchedule);

      const result = await backupApiService.getWorkspaceBackupStatus(namespace, workspaceName);

      expect(result.backupSchedule).toBeUndefined();
    });
  });
});
